UIDressStoreInfoItem = class("UIDressStoreInfoItem", IGUIWindow)

function UIDressStoreInfoItem:onLoad()
    self.id = 0
    self.stName = self:getChildWindow(0, GUIType.StaticText)
    self.btnAction = self:getChildWindow(1, GUIType.Button)
    self.btnUse = self:getChildWindow(0, GUIType.Button, self.btnAction)
    self.btnUnload = self:getChildWindow(1, GUIType.Button, self.btnAction)
    self.btnBuy = self:getChildWindow(2, GUIType.Button, self.btnAction)
    self.layDress = self:getChildWindow(2, GUIType.Layout)
    self.siIcon = self:getChildWindow(0, GUIType.StaticImage, self.layDress)
    self.stDesc = self:getChildWindow(1, GUIType.StaticText, self.layDress)

    self:updateLanguage()

    self:register()
end

function UIDressStoreInfoItem:register()
    self.btnUse:registerEvent(GUIEvent.ButtonClick, function()
        SoundUtil.playSound(SoundType.Click)
        GamePacketSender:sendBedWarUseStoreDress(self.id)
        UIDressStore:changeStatue(self.id, 4)
    end)

    self.btnUnload:registerEvent(GUIEvent.ButtonClick, function()
        SoundUtil.playSound(SoundType.Click)
        GamePacketSender:sendBedWarUnloadStoreDress(self.id)
        UIDressStore:changeStatue(self.id, 3)
    end)

    self.btnBuy:registerEvent(GUIEvent.ButtonClick, function()
        local dress = UIDressStore:getDressData(self.id)
        if dress then
            GUIStoreDressDetail:init(self.id, dress.Chip)
        end
    end)
end

function UIDressStoreInfoItem:updateLanguage()
    self.btnUse:SetText(Lang:getString("dress_shop_use"))
    self.btnBuy:SetText(Lang:getString("shop_btn_buy"))
    self.btnUnload:SetText(Lang:getString("dress_shop_unload"))
end

function UIDressStoreInfoItem:updateAndShow(id)
    self.id = id
    local config = DressConfig:findStoreDressById(id)
    local statue = UIDressStore:getStatuesById(id)
    self.stName:SetText(Lang:getString(config.Name))
    if statue == 0 then
        --LOCK
        self.btnUse:SetVisible(false)
        self.btnUnload:SetVisible(false)
        self.btnBuy:SetVisible(false)
    elseif statue == 2 or statue == 1 then
        --NOT_GET   NEW
        self.btnUse:SetVisible(false)
        self.btnUnload:SetVisible(false)
        self.btnBuy:SetVisible(true)
    elseif statue == 3 then
        --HAS_GET
        self.btnUse:SetVisible(true)
        self.btnUnload:SetVisible(false)
        self.btnBuy:SetVisible(false)
    elseif statue == 4 then
        --HAS_USE
        self.btnUse:SetVisible(false)
        self.btnUnload:SetVisible(true)
        self.btnBuy:SetVisible(false)
    end
    self.siIcon:SetImage(config.Icon)
    self.stDesc:SetText(Lang:getString(config.Describe))
end

function UIDressStoreInfoItem:cleanInfo()
    self.stName:SetText("")
    self.siIcon:SetImage("")
    self.stDesc:SetText("")
    self.btnUse:SetVisible(false)
    self.btnUnload:SetVisible(false)
    self.btnBuy:SetVisible(false)
end

return UIDressStoreInfoItem